# fallback_dispatcher.py
# Implements a tiered fallback chain: primary model -> smaller model -> static default.
import json
import time
from anthropic import Anthropic

client = Anthropic()

PRIMARY_MODEL = "claude-opus-4-5"
FALLBACK_MODEL = "claude-haiku-4-5"  # cheaper, faster
CONFIDENCE_THRESHOLD = 0.65
MAX_RETRIES = 2

def call_llm(model: str, system: str, user: str, attempt: int = 0) -> dict:
    """Call the LLM and return a parsed dict, or a parse_error refusal."""
    try:
        resp = client.messages.create(
            model=model,
            max_tokens=512,
            system=system,
            messages=[{"role": "user", "content": user}]
        )
        raw = resp.content[0].text.strip()
        # Strip markdown code fences that models sometimes emit
        if raw.startswith("```"):
            raw = raw.split("\n", 1)[1].rsplit("```", 1)[0].strip()
        return json.loads(raw)
    except json.JSONDecodeError as e:
        return {"status": "refused", "refusal_code": "parse_error",
                "confidence": 0.0, "answer": None,
                "caveat": f"Attempt {attempt}: parse error — {e}"}
    except Exception as e:
        return {"status": "refused", "refusal_code": "api_error",
                "confidence": 0.0, "answer": None, "caveat": str(e)}

def is_usable(response: dict) -> bool:
    """A response is usable if status is answered and confidence meets threshold."""
    return (
        response.get("status") == "answered"
        and response.get("confidence", 0) >= CONFIDENCE_THRESHOLD
    )

def dispatch_with_fallback(system: str, user: str) -> dict:
    # Tier 1: primary model with retries
    for attempt in range(MAX_RETRIES + 1):
        result = call_llm(PRIMARY_MODEL, system, user, attempt)
        if is_usable(result):
            result["_tier"] = "primary"
            return result
        if attempt < MAX_RETRIES:
            time.sleep(0.5 * (2 ** attempt))  # exponential backoff

    # Tier 2: smaller fallback model (one attempt)
    result = call_llm(FALLBACK_MODEL, system, user)
    if is_usable(result):
        result["_tier"] = "fallback_model"
        return result

    # Tier 3: static default / escalation signal
    return {
        "status": "fallback",
        "refusal_code": "max_fallbacks_exhausted",
        "confidence": 0.0,
        "answer": None,
        "caveat": "All automated tiers failed. Please review manually.",
        "_tier": "static_default"
    }

# Usage example
SYSTEM = """You are a structured JSON assistant. For every question return:
{"status": "answered", "confidence": 0.9, "answer": "your answer", "caveat": null}
Or a refusal object if you cannot answer reliably."""

result = dispatch_with_fallback(SYSTEM, "What is the capital of France?")
print(f"Tier: {result.get('_tier')}, Status: {result['status']}")
print(f"Answer: {result.get('answer')}")
